import { Task, User, Team, Assignment } from './types';

// --- In-memory "Database" ---
const tasks: Task[] = [
  { id: 'task-1', title: 'Implement login', description: 'Develop user authentication module', teamId: 'team-a', assigneeId: null, status: 'pending' },
  { id: 'task-2', title: 'Design database schema', description: 'Create ER diagrams for the project', teamId: 'team-a', assigneeId: 'user-1', status: 'in-progress' },
  { id: 'task-3', title: 'Write API documentation', description: 'Document all REST endpoints', teamId: 'team-b', assigneeId: null, status: 'pending' },
];

const users: User[] = [
  { id: 'user-1', name: 'Alice', email: 'alice@example.com' },
  { id: 'user-2', name: 'Bob', email: 'bob@example.com' },
  { id: 'user-3', name: 'Charlie', email: 'charlie@example.com' },
];

const teams: Team[] = [
  { id: 'team-a', name: 'Frontend Team', memberIds: ['user-1', 'user-2'] },
  { id: 'team-b', name: 'Backend Team', memberIds: ['user-3'] },
];

const assignments: Assignment[] = [
  { taskId: 'task-2', assigneeId: 'user-1', assignedAt: new Date() },
];

// --- DB Access Functions ---

export const getTaskById = (id: string): Task | undefined => {
  return tasks.find(task => task.id === id);
};

export const getUserById = (id: string): User | undefined => {
  return users.find(user => user.id === id);
};

export const getTeamById = (id: string): Team | undefined => {
  return teams.find(team => team.id === id);
};

export const updateTaskAssignee = (taskId: string, assigneeId: string | null): Task | undefined => {
  const taskIndex = tasks.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    return undefined;
  }
  tasks[taskIndex] = { ...tasks[taskIndex], assigneeId };

  // Update assignments table (simplified: just add/update if assigneeId is not null)
  if (assigneeId) {
    const existingAssignmentIndex = assignments.findIndex(a => a.taskId === taskId);
    if (existingAssignmentIndex !== -1) {
      assignments[existingAssignmentIndex] = { taskId, assigneeId, assignedAt: new Date() };
    } else {
      assignments.push({ taskId, assigneeId, assignedAt: new Date() });
    }
  } else {
    // If assignee is set to null, remove from assignments
    const existingAssignmentIndex = assignments.findIndex(a => a.taskId === taskId);
    if (existingAssignmentIndex !== -1) {
      assignments.splice(existingAssignmentIndex, 1);
    }
  }

  return tasks[taskIndex];
};
