```aether:src/routes/assignTask.ts
import { getTaskById, getUserById, getTeamById, updateTaskAssignee } from '../db';

type AssignTaskRequestBody = {
  assigneeId: string;
};

type AssignTaskParams = {
  taskId: string;
};

export const assignTask = async (
  params: AssignTaskParams,
  body: AssignTaskRequestBody
) => {
  const { taskId } = params;
  const { assigneeId } = body;

  // 1. Validate input
  if (!assigneeId) {
    return {
      status: 400,
      body: { success: false, message: 'Assignee ID is required.' }
    };
  }

  // 2. Find the task
  const task = getTaskById(taskId);
  if (!task) {
    return {
      status: 404,
      body: { success: false, message: `Task with ID '${taskId}' not found.` }
    };
  }

  // 3. Find the assignee
  const assignee = getUserById(assigneeId);
  if (!assignee) {
    return {
      status: 404,
      body: { success: false, message: `Assignee with ID '${assigneeId}' not found.` }
    };
  }

  // 4. Find the task's team
  const team = getTeamById(task.teamId);
  if (!team) {
    // This indicates a data inconsistency if a task exists but its team doesn't
    return {
      status: 500,
      body: { success: false, message: `Team with ID '${task.teamId}' associated with task '${taskId}' not found.` }
    };
  }

  // 5. Verify the assignee is a member of the task's team
  if (!team.memberIds.includes(assigneeId)) {
    return {
      status: 403, // Forbidden, or 400 Bad Request depending on desired specificity
      body: { success: false, message: `Assignee '${assigneeId}' is not a member of team '${team.name}' (ID: ${team.id}) for task '${taskId}'.` }
    };
  }

  // 6. Update the task assignment
  const updatedTask = updateTaskAssignee(taskId, assigneeId);

  if (!updatedTask) {
    // Should ideally not happen if getTaskById found it, but good for robustness
    return {
      status: 500,
      body: { success: false, message: `Failed to update task '${taskId}'.` }
    };
  }

  return {
    status: 200,
    body: { success: true, message: 'Task assigned successfully.', task: updatedTask }
  };
};
