import { Hono } from 'hono';
import { assignTask } from './routes/assignTask';

const app = new Hono();

// Middleware to parse JSON body
app.use('*', async (c, next) => {
  if (c.req.method === 'POST' || c.req.method === 'PUT') {
    try {
      const body = await c.req.json();
      c.set('parsedBody', body);
    } catch (e) {
      return c.json({ success: false, message: 'Invalid JSON body' }, 400);
    }
  }
  await next();
});

app.post('/tasks/:taskId/assign', async (c) => {
  const taskId = c.req.param('taskId');
  const body = c.get('parsedBody'); // Get parsed body from middleware

  const result = await assignTask({ taskId }, body);

  return c.json(result.body, result.status);
});

// Basic health check route
app.get('/', (c) => {
  return c.json({ message: 'Task Assignment Service is running!' });
});

export default app;
